package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.concurrent.ConcurrentHashMap;

/**
 * In-memory planner bandit using UCB1-style ranking.
 */
public final class InMemoryBanditPolicy implements BanditPolicy {

	private static final class ArmStats {
		private double rewardSum;
		private long pulls;

		private void add(double reward) {
			rewardSum += reward;
			pulls++;
		}
	}

	private final Map<String, Map<String, ArmStats>> byRegion = new ConcurrentHashMap<>();

	@Override
	public List<String> selectPlanners(String regionFingerprint, List<String> available, int k) {
		if (available == null || available.isEmpty()) {
			return List.of();
		}
		int limit = Math.max(1, Math.min(k, available.size()));
		Map<String, ArmStats> regionStats = byRegion.getOrDefault(regionKey(regionFingerprint), Map.of());
		long totalPulls = 0L;
		for (ArmStats stats : regionStats.values()) {
			totalPulls += Math.max(1L, stats.pulls);
		}
		long safeTotalPulls = Math.max(1L, totalPulls);

		List<String> ranked = new ArrayList<>(available);
		ranked.sort(Comparator.comparingDouble((String planner) -> ucbScore(planner, regionStats, safeTotalPulls))
				.reversed()
				.thenComparing(String::compareTo));

		return ranked.subList(0, limit);
	}

	private double ucbScore(String planner, Map<String, ArmStats> regionStats, long totalPulls) {
		ArmStats stats = regionStats.get(planner);
		if (stats == null || stats.pulls == 0L) {
			return Double.POSITIVE_INFINITY;
		}
		double mean = stats.rewardSum / stats.pulls;
		double bonus = Math.sqrt((2.0d * Math.log(totalPulls + 1.0d)) / stats.pulls);
		return mean + bonus;
	}

	@Override
	public void reportOutcome(String regionFingerprint, String chosenPlanner, double reward) {
		if (chosenPlanner == null || chosenPlanner.isBlank()) {
			return;
		}
		String key = regionKey(regionFingerprint);
		byRegion.compute(key, (ignored, current) -> {
			Map<String, ArmStats> next = current == null ? new HashMap<>() : new HashMap<>(current);
			ArmStats stats = next.computeIfAbsent(chosenPlanner, ignoredPlanner -> new ArmStats());
			stats.add(reward);
			return next;
		});
	}

	private String regionKey(String regionFingerprint) {
		return Objects.requireNonNullElse(regionFingerprint, "unknown");
	}
}
